def seriesbounds(values: np.ndarray, lowerpad: float, upperpad: float, fallback: tuple[float, float]) -> tuple[float, float]:
 if values.size == 0:
 return fallback
 ymin = float(np.min(values))
 ymax = float(np.max(values))
 if abs(ymax - ymin) < 1e-6:
 center = 0.5 (ymax + ymin)
 half = max(lowerpad, upperpad, 0.05)
 return center - half, center + half
 return ymin - lowerpad, ymax + upperpad

