class SimObservationInterface:
 """MuJoCo sensor bridge that populates State like a robot-side observer."""
 def init(self, model: mujoco.MjModel, data: mujoco.MjData):
 self.model = model
 self.data = data
 self.sensorslices = {
 sensorname: self.sensorslice(sensorname)
 for sensorname in (
 "torsopos",
 "imuquat",
 "imugyro",
 "imuacc",
 "imuvel",
 FOOTPOSSENSORNAMES,
 FOOTTOUCHSENSORNAMES,
 JOINTPOSSENSORNAMES,
 JOINTVELSENSORNAMES,
 )
 }
 def sensorslice(self, sensorname: str) -> slice:
 sensorid = mujoco.mjname2id(self.model, mujoco.mjtObj.mjOBJSENSOR, sensorname)
 sensoradr = self.model.sensoradr[sensorid]
 sensordim = self.model.sensordim[sensorid]
 return slice(sensoradr, sensoradr + sensordim)
 def readsensor(self, sensorname: str) -> np.ndarray:
 return np.array(self.data.sensordata[self.sensorslices[sensorname]], copy=True)
 def torsopose(self) -> tuple[np.ndarray, np.ndarray, np.ndarray]:
 torsoid = mujoco.mjname2id(self.model, mujoco.mjtObj.mjOBJBODY, "torso")
 position = self.data.xpos[torsoid].copy()
 rotation = self.data.xmat[torsoid].reshape(3, 3).copy()
 quat = self.data.xquat[torsoid].copy()
 return position, rotation, quat
 def bodyframefeet(self) -> np.ndarray:
 torsoposition, torsorotation, = self.torsopose()
 feet = np.zeros((3, 4))
 for siteindex, sitename in enumerate(FOOTSITENAMES):
 siteid = mujoco.mjname2id(self.model, mujoco.mjtObj.mjOBJSITE, sitename)
 offsetworld = self.data.sitexpos[siteid] - torsoposition
 feet[:, siteindex] = torsorotation.T @ offsetworld
 return feet
 def measuredbodyframefeet(self, torsoposition: np.ndarray, torsoquat: np.ndarray) -> np.ndarray:
 torsorotation = quat2mat(torsoquat)
 feet = np.zeros((3, 4))
 for siteindex, sensorname in enumerate(FOOTPOSSENSORNAMES):
 footworld = self.readsensor(sensorname)
 feet[:, siteindex] = torsorotation.T @ (footworld - torsoposition)
 return feet
 def measuredjointangles(self) -> np.ndarray:
 jointvalues = np.array([self.readsensor(sensorname)[0] for sensorname in JOINTPOSSENSORNAMES], dtype=float)
 jointvalues = jointvalues.reshape(4, 3).T
 jointvalues[2, :] += jointvalues[1, :]
 return jointvalues
 def measuredjointvelocities(self) -> np.ndarray:
 jointvalues = np.array([self.readsensor(sensorname)[0] for sensorname in JOINTVELSENSORNAMES], dtype=float)
 jointvalues = jointvalues.reshape(4, 3).T
 jointvalues[2, :] += jointvalues[1, :]
 return jointvalues
 def contactforces(self) -> np.ndarray:
 return np.array([self.readsensor(sensorname)[0] for sensorname in FOOTTOUCHSENSORNAMES], dtype=float)
 def syncstate(
 self,
 state: State,
 stancestateblend: float,
 swingstateblend: float,
 contactthreshold: float,
 ) -> None:
 torsoposition = self.readsensor("torsopos")
 torsoquat = self.readsensor("imuquat")
 measuredfeet = self.measuredbodyframefeet(torsoposition, torsoquat)
 state.measuredfootlocations = measuredfeet
 state.measuredjointangles = self.measuredjointangles()
 state.measuredjointvelocities = self.measuredjointvelocities()
 state.jointangles = state.measuredjointangles.copy()
 state.jointvelocities = state.measuredjointvelocities.copy()
 state.bodyposition = torsoposition
 state.bodyvelocity = self.readsensor("imuvel")
 state.angularvelocity = self.readsensor("imugyro")
 state.footforces = self.contactforces()
 state.contactestimate = state.footforces > contactthreshold
 for legindex in range(4):
 blend = stancestateblend if state.contactestimate[legindex] else swingstateblend
