class SimHardwareInterface:
 """Servo-like actuator adapter that tracks joint targets through MuJoCo motors."""
 def init(
 self,
 model: mujoco.MjModel,
 data: mujoco.MjData,
 kp: float,
 kd: float,
 torquelimit: float,
 ):
 self.model = model
 self.data = data
 self.kp = kp
 self.kd = kd
 self.torquelimit = torquelimit
 self.targetqpos = np.zeros(len(JOINTNAMES))
 def setinitialpose(self, jointangles: np.ndarray, basez: float) -> None:
 self.targetqpos = jointtargetarray(jointangles)
 self.data.qpos[:3] = np.array([0.0, 0.0, basez])
 self.data.qpos[3:7] = np.array([1.0, 0.0, 0.0, 0.0])
 for index, jointname in enumerate(JOINTNAMES):
 jointid = mujoco.mjname2id(self.model, mujoco.mjtObj.mjOBJJOINT, jointname)
 self.data.qpos[self.model.jntqposadr[jointid]] = self.targetqpos[index]
 self.data.qvel[:] = 0.0
 self.data.ctrl[:] = 0.0
 mujoco.mjforward(self.model, self.data)
 def setactuatorpostions(self, jointangles: np.ndarray) -> None:
 self.targetqpos = jointtargetarray(jointangles)
 def setactuatorposition(self, jointangle: float, axis: int, leg: int) -> None:
 jointname = JOINTNAMES[leg 3 + axis]
 targets = dict(zip(JOINTNAMES, self.targetqpos.tolist()))
 if axis == 2:
 hipjointname = JOINTNAMES[leg 3 + 1]
 targets[jointname] = float(jointangle - targets[hipjointname])
 else:
 targets[jointname] = float(jointangle)
 self.targetqpos = np.array([targets[name] for name in JOINTNAMES], dtype=float)
 def computepdtorques(self) -> np.ndarray:
 torques = np.zeros(len(JOINTNAMES))
 for index, jointname in enumerate(JOINTNAMES):
 jointid = mujoco.mjname2id(self.model, mujoco.mjtObj.mjOBJJOINT, jointname)
 qposaddr = self.model.jntqposadr[jointid]
 qveladdr = self.model.jntdofadr[jointid]
 positionerror = self.targetqpos[index] - self.data.qpos[qposaddr]
 velocityerror = -self.data.qvel[qveladdr]
 torques[index] = np.clip(
 self.kp positionerror + self.kd velocityerror,
 -self.torquelimit,
 self.torquelimit,
 )
 return torques
 def step(self, substeps: int) -> None:
 for in range(substeps):
 self.data.ctrl[:] = self.computepdtorques()
 mujoco.mjstep(self.model, self.data)
class SimControlClock:
 """Control-rate clock that advances MuJoCo substeps like a robot-side loop."""
 def init(self, simdt: float, controldt: float, viewer=None):
 self.simdt = simdt
 self.controldt = controldt
 self.controlinterval = max(1, int(round(controldt / simdt)))
 self.viewer = viewer
 self.nextwalltime = time.perfcounter()
 def totalticks(self, duration: float) -> int:
 return max(1, int(duration / self.controldt))
