 return self.viewer.lock() if self.viewer is not None else contextlib.nullcontext()
 def finishtick(self) -> None:
 if self.viewer is None:
 return
 self.viewer.sync()
 self.nextwalltime += self.controldt
 sleeptime = self.nextwalltime - time.perfcounter()
 if sleeptime > 0:
 time.sleep(sleeptime)
