 previousvalues: dict[str, float],
 currentvalues: dict[str, float],
 alpha: float,
 ) -> dict[str, float]:
 keys = set(previousvalues) set(currentvalues)
 return {
 key: (1.0 - alpha) previousvalues[key] + alpha currentvalues[key]
 for key in keys
 }
 @staticmethod
 def stepvalues(basevalues: dict[str, float], step: object None, allowedkeys: set[str]) -> dict[str, float]:
 values = dict(basevalues)
 if step is None:
