@dataclass(frozen=True)
class TaskStep:
 """One scheduled task segment."""
 mode: str
 duration: float None = None
 params: dict[str, float] None = None
 transitiontime: float None = None
class TaskScheduler:
 """High-level task scheduler for simulated command sequencing."""
 def init(
 self,
 steps: list[TaskStep],
 activationdelay: float = 0.0,
 defaulttransitiontime: float = 0.0,
 ):
 if not steps:
 raise ValueError("TaskScheduler requires at least one task step.")
 self.activationdelay = max(0.0, float(activationdelay))
 self.defaulttransitiontime = max(0.0, float(defaulttransitiontime))
 self.steps = [self.validatestep(step) for step in steps]
 @classmethod
 def fromargs(cls, args) -> "TaskScheduler":
 if args.tasksequence:
 steps = cls.parsesequence(args.tasksequence)
 else:
 steps = cls.defaultsequence(args.mode, args.settle)
 return cls(
 steps,
 activationdelay=args.activationdelay,
 defaulttransitiontime=args.transitiontime,
 )
 @staticmethod
 def defaultsequence(mode: str, settle: float) -> list[TaskStep]:
 if mode == "rest":
 return [TaskStep("rest")]
 if settle > 0.0:
 return [TaskStep("rest", duration=settle), TaskStep("trot")]
 return [TaskStep("trot")]
 @staticmethod
 def parsesequence(sequencetext: str) -> list[TaskStep]:
 steps: list[TaskStep] = []
 tokens = [token.strip() for token in sequencetext.split(",") if token.strip()]
 if not tokens:
 raise ValueError("tasksequence is empty.")
 for index, token in enumerate(tokens):
 steptext, paramtext = TaskScheduler.splittoken(token)
 parts = [part.strip() for part in steptext.split(":")]
 if len(parts) > 2:
 raise ValueError(f"Invalid task token {token}.")
 mode = parts[0].lower()
 if mode not in TASKMODES:
 raise ValueError(f"Unsupported task mode {mode}.")
 duration: float None = None
 if len(parts) == 2 and parts[1]:
 durationtext = parts[1].lower()
 if durationtext in ("inf", "forever"):
 duration = None
 else:
 duration = float(durationtext)
 elif len(parts) == 1 and index < len(tokens) - 1:
 raise ValueError(
 "Only the last task step may omit duration. "
 "Example: rest:1.0,trot:2.0,rest."
 )
 params = TaskScheduler.parseparams(paramtext)
 transitiontime = params.pop("transitiontime", None)
 steps.append(
 TaskStep(
 mode=mode,
 duration=duration,
 params=params,
 transitiontime=transitiontime,
 )
 )
 return steps
 def validatestep(self, step: TaskStep) -> TaskStep:
 mode = step.mode.lower()
 if mode not in TASKMODES:
 raise ValueError(f"Unsupported task mode {mode}.")
 if step.duration is not None and step.duration < 0.0:
 raise ValueError("Task duration must be non-negative.")
 params = dict(step.params or {})
 for key, value in params.items():
 if key not in TASKPARAMALIASES.values():
 raise ValueError(f"Unsupported task parameter {key}.")
 params[key] = float(value)
 transitiontime = self.defaulttransitiontime if step.transitiontime is None else float(step.transitiontime)
 if transitiontime < 0.0:
 raise ValueError("Task transitiontime must be non-negative.")
 return TaskStep(
 mode=mode,
 duration=step.duration,
 params=params,
 transitiontime=transitiontime,
 )
 @staticmethod
 def splittoken(token: str) -> tuple[str, str None]:
 if "@" not in token:
 return token, None
 steptext, paramtext = token.split("@", 1)
 return steptext.strip(), paramtext.strip()
 @staticmethod
 def parseparams(paramtext: str None) -> dict[str, float]:
 if not paramtext:
 return {}
 params: dict[str, float] = {}
 assignments = [item.strip() for item in paramtext.replace(" ", ";").split(";") if item.strip()]
 if not assignments:
 raise ValueError("Task parameter list is empty after @.")
 for assignment in assignments:
 if "=" not in assignment:
 raise ValueError(f"Invalid task parameter {assignment}.")
 rawkey, rawvalue = assignment.split("=", 1)
 key = rawkey.strip().lower()
 value = rawvalue.strip()
 if key not in TASKPARAMALIASES:
 raise ValueError(f"Unsupported task parameter {rawkey}.")
 params[TASKPARAMALIASES[key]] = float(value)
 return params
 def iswaiting(self, simtime: float) -> bool:
 return simtime < self.activationdelay
 def stepat(self, simtime: float) -> TaskStep:
 return self.stepinfoat(simtime)[1]
 def stepinfoat(self, simtime: float) -> tuple[int, TaskStep]:
 if self.iswaiting(simtime):
 raise ValueError("Task mode is undefined before activation.")
 remainingtime = simtime - self.activationdelay
 for stepindex, step in enumerate(self.steps):
 if step.duration is None or remainingtime < step.duration:
 return stepindex, step
 remainingtime -= step.duration
 return len(self.steps) - 1, self.steps[-1]
 def stepelapsedat(self, simtime: float) -> tuple[int, TaskStep, float]:
 if self.iswaiting(simtime):
 raise ValueError("Task mode is undefined before activation.")
